29	export type CheckpointTreeItem =
30	  | { kind: "group";      label: string; checkpoints: Checkpoint[]; port: number; startIndex: number; repoPath: string }
31	  | { kind: "checkpoint"; cp: Checkpoint; port: number; index: number; repoPath: string }
32	  | { kind: "summary";    checkpointId: string; text: string }
33	  | { kind: "dir";        label: string; fullPath: string; absPath: string; children: CheckpointTreeItem[] }
34	  | { kind: "file";       name: string;  fullPath: string; absPath: string; checkpointId: string; port: number };
