36	function fetchJson<T>(url: string): Promise<T> {
37	  return new Promise((resolve, reject) => {
38	    const req = httpGet(url, (res) => {
39	      const chunks: Buffer[] = [];
40	      res.on("data", (c: Buffer) => chunks.push(c));
41	      res.on("end", () => {
42	        try { resolve(JSON.parse(Buffer.concat(chunks).toString("utf8"))); }
43	        catch (e) { reject(e); }
44	      });
45	    });
46	    req.on("error", reject);
47	    req.setTimeout(5000, () => { req.destroy(); reject(new Error("timeout")); });
48	  });
49	}
50	
51	function buildItems(
52	  paths: string[],
53	  checkpointId: string,
54	  port: number,
55	  repoPath: string,
56	): CheckpointTreeItem[] {
57	  interface Node { children: Map<string, Node>; isFile: boolean; }
58	  const root = new Map<string, Node>();
59	
60	  for (const p of paths) {
61	    const parts = p.split("/");
62	    let nodes = root;
63	    for (let i = 0; i < parts.length; i++) {
64	      if (!nodes.has(parts[i])) {
65	        nodes.set(parts[i], { children: new Map(), isFile: i === parts.length - 1 });
66	      }
67	      nodes = nodes.get(parts[i])!.children;
68	    }
69	  }
70	
71	  function toItems(nodes: Map<string, Node>, prefix: string): CheckpointTreeItem[] {
72	    return Array.from(nodes.entries()).map(([name, node]) => {
73	      const fullPath = prefix ? `${prefix}/${name}` : name;
74	      const absPath  = join(repoPath, fullPath);
75	      if (node.isFile) {
76	        return { kind: "file", name, fullPath, absPath, checkpointId, port } as CheckpointTreeItem;
77	      }
78	      return { kind: "dir", label: name, fullPath, absPath, children: toItems(node.children, fullPath) } as CheckpointTreeItem;
79	    });
80	  }
81	
82	  return toItems(root, "");
83	}
