85	export class CheckpointTreeProvider
86	  implements vscode.TreeDataProvider<CheckpointTreeItem>
87	{
88	  private _onDidChangeTreeData = new vscode.EventEmitter<void>();
89	  readonly onDidChangeTreeData = this._onDidChangeTreeData.event;
90	
91	  private sessionCheckpoints: Checkpoint[] = [];
92	  private branchCheckpoints: Checkpoint[] = [];
93	  private currentBranch: string | null = null;
94	  private currentPort: number | null = null;
95	  private currentRepoPath: string = "";
96	
97	  async setSession(sessionId: string, port: number): Promise<void> {
98	    this.currentPort = port;
99	
100	    // Fetch session info and checkpoints in parallel.
101	    const [allSessionCheckpoints, sessionInfo] = await Promise.all([
102	      fetchJson<Checkpoint[]>(
103	        `http://localhost:${port}/api/v2/sessions/${encodeURIComponent(sessionId)}/checkpoints`,
104	      ).catch(() => [] as Checkpoint[]),
105	      fetchJson<{ cwd: string; branch: string | null; updatedAt: string; isLive: boolean }>(
106	        `http://localhost:${port}/api/sessions/${encodeURIComponent(sessionId)}`,
107	      ).catch(() => ({ cwd: "", branch: null, updatedAt: "", isLive: false })),
108	    ]);
109	
110	    if (sessionInfo.cwd) this.currentRepoPath = sessionInfo.cwd;
111	
112	    // For completed sessions, restrict "Session" to checkpoints that were created
113	    // during the agent's active run (at or before the last log event, plus a small
114	    // buffer for indexing lag). Post-session commits tagged to the same session ID
115	    // by Entire are excluded here and will appear in Branch History instead.
116	    let sessionCheckpoints = allSessionCheckpoints;
117	    if (!sessionInfo.isLive && sessionInfo.updatedAt) {
118	      const cutoff = new Date(new Date(sessionInfo.updatedAt).getTime() + 2 * 60 * 1000);
119	      sessionCheckpoints = allSessionCheckpoints.filter(
120	        (cp) => !cp.createdAt || new Date(cp.createdAt) <= cutoff,
121	      );
122	    }
123	
124	    // Deduplicate branch history against session checkpoints so each commit
125	    // appears in exactly one section.
126	    const sessionIds = new Set(sessionCheckpoints.map((cp) => cp.checkpointId));
127	
128	    let branchCheckpoints: Checkpoint[] = [];
129	    try {
130	      if (sessionInfo.cwd && sessionInfo.branch) {
131	        this.currentBranch = sessionInfo.branch;
132	        const log = await fetchJson<{ entries: BranchLogEntry[] }>(
133	          `http://localhost:${port}/api/branch-log?localPath=${encodeURIComponent(sessionInfo.cwd)}&branch=${encodeURIComponent(sessionInfo.branch)}`,
134	        );
135	
136	        // Build a message map from ALL branch-log entries before dedup, so session
137	        // checkpoints missing a commit message can fall back to the branch-log value.
138	        const branchMessageMap = new Map<string, string>();
139	        const branchHashMap    = new Map<string, string>();
140	        for (const entry of log.entries) {
141	          if (entry.commitMessage) branchMessageMap.set(entry.checkpointId, entry.commitMessage);
142	          if (entry.commitHash)    branchHashMap.set(entry.checkpointId, entry.commitHash);
143	        }
144	
145	        // Enrich session checkpoints that have a null commit message.
146	        sessionCheckpoints = sessionCheckpoints.map((cp) => ({
147	          ...cp,
148	          commitMessage: cp.commitMessage ?? branchMessageMap.get(cp.checkpointId) ?? null,
149	          commitHash:    cp.commitHash    ?? branchHashMap.get(cp.checkpointId)    ?? null,
150	        }));
151	
152	        const seen = new Set<string>(sessionIds);
153	        for (const entry of log.entries) {
154	          if (!seen.has(entry.checkpointId)) {
155	            seen.add(entry.checkpointId);
156	            branchCheckpoints.push({
157	              checkpointId:  entry.checkpointId,
158	              createdAt:     entry.createdAt,
159	              filesTouched:  entry.filesTouched,
160	              summary:       entry.summary,
161	              commitMessage: entry.commitMessage,
162	              commitHash:    entry.commitHash,
163	            });
164	          }
165	        }
166	      }
167	    } catch { /* branch-log unavailable or repo not registered */ }
168	
169	    this.sessionCheckpoints = sessionCheckpoints;
170	    this.branchCheckpoints  = branchCheckpoints;
171	    if (branchCheckpoints.length === 0) this.currentBranch = null;
172	    this._onDidChangeTreeData.fire();
173	  }
