175	  getTreeItem(element: CheckpointTreeItem): vscode.TreeItem {
176	    if (element.kind === "group") {
177	      const item = new vscode.TreeItem(element.label, vscode.TreeItemCollapsibleState.Expanded);
178	      item.iconPath = new vscode.ThemeIcon("history");
179	      return item;
180	    }
181	    if (element.kind === "checkpoint") {
182	      const cp      = element.cp;
183	      const shortId = cp.checkpointId.slice(0, 8);
184	      const msg     = cp.commitMessage;
185	      const label   = msg
186	        ? (msg.length > 60 ? msg.slice(0, 59) + "…" : msg)
187	        : shortId;
188	
189	      const collapsible = element.index === 0
190	        ? vscode.TreeItemCollapsibleState.Expanded
191	        : vscode.TreeItemCollapsibleState.Collapsed;
192	      const item = new vscode.TreeItem(label, collapsible);
193	
194	      const commitShort = cp.commitHash ? cp.commitHash.slice(0, 8) : null;
195	      item.description  = commitShort ? `${shortId} · ${commitShort}` : shortId;
196	
197	      const tooltip = new vscode.MarkdownString("", true);
198	      tooltip.appendMarkdown(`**Checkpoint:** \`${cp.checkpointId}\`\n\n`);
199	      if (cp.commitHash) tooltip.appendMarkdown(`**Commit:** \`${cp.commitHash}\`\n\n`);
200	      if (msg) tooltip.appendMarkdown(msg);
201	      item.tooltip  = tooltip;
202	      item.iconPath = new vscode.ThemeIcon("git-commit");
203	      item.contextValue = "checkpoint";
204	      return item;
205	    }
206	    if (element.kind === "summary") {
207	      const item = new vscode.TreeItem("summary.txt", vscode.TreeItemCollapsibleState.None);
208	      item.iconPath = new vscode.ThemeIcon("note");
209	      item.tooltip = element.text;
210	      item.command = {
211	        command: "gossamer.showCheckpointSummary",
212	        title: "Show Summary",
213	        arguments: [element.checkpointId, element.text],
214	      };
215	      return item;
216	    }
217	    if (element.kind === "dir") {
218	      const item = new vscode.TreeItem(element.label, vscode.TreeItemCollapsibleState.Expanded);
219	      item.resourceUri = vscode.Uri.file(element.absPath);
220	      return item;
221	    }
222	    // file
223	    const item = new vscode.TreeItem(element.name, vscode.TreeItemCollapsibleState.None);
224	    item.resourceUri = vscode.Uri.file(element.absPath);
225	    item.tooltip = element.fullPath;
226	    item.command = {
227	      command: "gossamer.showCheckpointDiff",
228	      title: "Show Diff",
229	      arguments: [element.checkpointId, element.fullPath, element.port],
230	    };
231	    return item;
232	  }
233	
234	  getChildren(element?: CheckpointTreeItem): vscode.ProviderResult<CheckpointTreeItem[]> {
235	    if (!element) {
236	      if (!this.currentPort) return [];
237	      const port = this.currentPort;
238	      const repoPath = this.currentRepoPath;
239	      const groups: CheckpointTreeItem[] = [
240	        { kind: "group", label: "Session", checkpoints: this.sessionCheckpoints, port, startIndex: 0, repoPath },
241	      ];
242	      if (this.branchCheckpoints.length > 0) {
243	        const branchLabel = this.currentBranch
244	          ? `Branch History (${this.currentBranch})`
245	          : "Branch History";
246	        groups.push({
247	          kind: "group",
248	          label: branchLabel,
249	          checkpoints: this.branchCheckpoints,
250	          port,
251	          startIndex: this.sessionCheckpoints.length,
252	          repoPath,
253	        });
254	      }
255	      return groups;
256	    }
257	    if (element.kind === "group") {
258	      return element.checkpoints.map((cp, i) => ({
259	        kind: "checkpoint" as const,
260	        cp,
261	        port: element.port,
262	        index: element.startIndex + i,
263	        repoPath: element.repoPath,
264	      }));
265	    }
266	    if (element.kind === "checkpoint") {
267	      const cp = element.cp;
268	      const SEP = "─".repeat(68);
269	      const section = (title: string, body: string) => `${SEP}\n${title}\n${SEP}\n${body}`;
270	
271	      const lines: string[] = [];
272	      lines.push(`Checkpoint: ${cp.checkpointId}`);
273	      if (cp.createdAt) lines.push(`Created:    ${new Date(cp.createdAt).toLocaleString()}`);
274	      if (cp.commitHash) lines.push(`Commit:     ${cp.commitHash}${cp.commitMessage ? `  ${cp.commitMessage}` : ""}`);
275	
276	      const s = cp.summary;
277	      if (s) {
278	        if (s.intent)  lines.push("", section("Intent", s.intent));
279	        if (s.outcome) lines.push("", section("Outcome", s.outcome));
280	        if (s.openItems.length > 0) {
281	          const body = s.openItems.map((o) => `[${o.status.padEnd(11)}] ${o.text}`).join("\n");
