  });

  // GET /api/repos/current — return the config entry for the repo this server is running against
  app.get("/api/repos/current", (_req, res) => {
    try {
      const current = repoDir
        ? readConfig().repos.find((r) => r.localPath === repoDir) ?? null
        : null;
