  const i = args.indexOf(flag);
  return i !== -1 && args[i + 1] ? args[i + 1] : def;
};

const tryRealpath = (p: string): string => { try { return realpathSync(p); } catch { return p; } };

const defaultDb   = `${process.env.HOME ?? "~"}/.claude/hook-handler.db`;
